<?php
declare(strict_types=1);
namespace App\Core\System;
use PDO;
final readonly class HealthService{public function __construct(private HealthRepository $healthRepository,private LogRepository $logRepository,private PDO $pdo){} public function listHealthChecks(): array {return $this->healthRepository->listDefinitionsWithLastResult(100);} public function runHealthCheck(int $id,?int $tenantId,?int $userId,?string $ipAddress,?string $userAgent): string {$def=$this->healthRepository->findDefinitionById($id); if($def===null){return 'Health check no encontrado.';} $start=microtime(true); $status='error'; $message='No se pudo ejecutar el health check.'; try{$type=strtolower(trim((string)($def['check_type']??''))); if(in_array($type,['db','database'],true)){$this->pdo->query('SELECT 1'); $status='ok'; $message='Health check ejecutado correctamente.';}}catch(\Throwable){} $ms=(int)round((microtime(true)-$start)*1000); $this->healthRepository->insertResult($id,$status,$ms,$message); $this->logRepository->insert([':tenant_id'=>$tenantId,':user_id'=>$userId,':level'=>$status==='ok'?'info':'error',':channel'=>'system.health',':message'=>$message,':context'=>json_encode(['health_check_id'=>$id,'status'=>$status,'response_time_ms'=>$ms], JSON_UNESCAPED_UNICODE),':ip_address'=>$ipAddress,':user_agent'=>$userAgent]); return $message;}}
